/**
 * Resolve legacy URL for a QR-code label like "Band 1 - Level 1 Lied 5"
 * contentType: "video" -> /levelX/liedY/, "audio" -> /levelX/liedY_play/
 */
export function getLegacyUrl(label: string | null, contentType: string): string | null {
  if (!label) return null;
  const m = label.match(/Level\s+(\d+)\s+Lied\s+(\d+)/i);
  if (!m) return null;
  const kind = contentType === "audio" ? "play" : "video";
  const key = `L${m[1]}_S${m[2]}_${kind}`;
  return LEGACY_QR_REDIRECTS[key] ?? null;
}